      <rect x="280" y="141" width="29" height="24" rx="4" fill="#38bdf8" opacity="0.85"/>
      <text x="650" y="157" fill="#f4f4f5" font-size="13.5" font-weight="700" text-anchor="end">2</text>
      <text x="20" y="212" fill="#d4d4d8" font-size="13.5">清算機関</text>
      <rect x="280" y="196" width="29" height="24" rx="4" fill="#38bdf8" opacity="0.85"/>
